"use client";

import { useWavesurfer } from "@wavesurfer/react";
import { ExternalLink, Loader2, Pause, Play } from "lucide-react";
import { useTranslations } from "next-intl";
import { useEffect, useMemo, useRef, useState } from "react";
import Hover from "wavesurfer.js/dist/plugins/hover.esm.js";
import { cn } from "@/lib/utils";

interface AudioBubblePlayerProps {
  src: string;
  /** When `true`, the player sits inside the visitor's own bubble
   *  (dark surface in light theme, light in dark theme) — the
   *  internal palette inverts to match. */
  onDark?: boolean;
}

/**
 * Brand-themed voice-note player. Replaces the browser's native
 * `<audio controls>` with a wavesurfer.js waveform + a single
 * play/pause affordance — matches the FE app's `AudioPlayer` (its
 * pattern is the source of this port).
 *
 * **Theme adaptation**: wavesurfer renders to `<canvas>` which can't
 * resolve CSS variables — we read the relevant `--wx-*` tokens on
 * mount and pass real hex strings to wavesurfer. The `onDark` flag
 * flips the palette so the same component reads correctly on the
 * visitor's own dark bubble AND the operator's elevated bubble.
 *
 * **Hover plugin** gives visitors a thin vertical line + tooltip
 * showing the time position under the cursor — the standard
 * messenger UX for scrubbing through a voice note.
 */
export function AudioBubblePlayer({ src, onDark = false }: AudioBubblePlayerProps) {
  const t = useTranslations("messages");
  const containerRef = useRef<HTMLDivElement>(null);
  const [colors, setColors] = useState<{
    wave: string;
    progress: string;
    hoverLine: string;
  } | null>(null);
  const [loadError, setLoadError] = useState(false);

  // Resolve theme tokens to concrete hex strings on mount — wavesurfer
  // needs RGB/hex, not CSS-var references. Re-runs whenever `onDark`
  // changes (defensive — the flag is stable in practice but the cost
  // is one extra read).
  useEffect(() => {
    // Read the tokens off the CONTAINER, not `document.documentElement`
    // — in the React-component embed the `--wx-*` vars live on the
    // Shadow DOM host, never the host page's `<html>`, so reading from
    // `documentElement` would resolve to empty and the waveform would
    // always use the hardcoded fallbacks. The container inherits the
    // vars in every embed mode.
    const el = containerRef.current;
    if (!el) return;
    const styles = getComputedStyle(el);
    const primary = styles.getPropertyValue("--wx-primary").trim() || "#121314";
    const primaryFg = styles.getPropertyValue("--wx-primary-fg").trim() || "#ffffff";
    const fgMuted = styles.getPropertyValue("--wx-fg-muted").trim() || "#6b7280";
    if (onDark) {
      // Visitor's own bubble — wave on the bubble's own foreground
      // colour, dimmed for the unplayed portion.
      setColors({
        wave: hexToRgba(primaryFg, 0.35),
        progress: primaryFg,
        hoverLine: primaryFg,
      });
    } else {
      setColors({
        wave: fgMuted,
        progress: primary,
        hoverLine: primary,
      });
    }
  }, [onDark]);

  const plugins = useMemo(() => {
    if (!colors) return [];
    return [
      Hover.create({
        lineColor: colors.hoverLine,
        lineWidth: 1,
        labelBackground: colors.hoverLine,
        labelColor: onDark ? "#121314" : "#ffffff",
        labelSize: "10px",
      }),
    ];
  }, [colors, onDark]);

  // Match the FE app's fetch params — `credentials: "omit"` so the
  // browser doesn't attach cookies, which avoids the CORS preflight
  // failures cookies sometimes trigger on bare-CDN sources.
  const fetchParams = useMemo<RequestInit>(() => ({ credentials: "omit" }), []);

  // Skip the hook entirely until the palette is resolved — otherwise
  // wavesurfer mounts with default (visible) blue colours for a
  // frame before we swap them in. Also skip once we've recorded a
  // load error so wavesurfer doesn't retry forever.
  const { wavesurfer, isReady, isPlaying, currentTime } = useWavesurfer({
    container: containerRef,
    url: colors && !loadError ? src : undefined,
    waveColor: colors?.wave,
    progressColor: colors?.progress,
    cursorColor: colors?.progress,
    barWidth: 2,
    barRadius: 2,
    cursorWidth: 1,
    height: 24,
    // Voice notes are short — the visitor never needs to scroll the
    // waveform, and wavesurfer's internal scroll element would
    // otherwise paint a horizontal scrollbar under the wave on hover.
    hideScrollbar: true,
    plugins,
    fetchParams,
  });

  // Surface a fallback when the audio can't be loaded (CORS-blocked
  // source, 404, etc.) — keeps the bubble from sitting on a forever
  // spinner. Visitors get an "Open" link that opens the raw URL in
  // a new tab as the escape hatch.
  useEffect(() => {
    if (!wavesurfer) return;
    const onError = () => setLoadError(true);
    wavesurfer.on("error", onError);
    return () => {
      wavesurfer.un("error", onError);
    };
  }, [wavesurfer]);

  const handlePlayPause = () => {
    wavesurfer?.playPause();
  };

  if (loadError) {
    return (
      <a
        href={src}
        target="_blank"
        rel="noopener"
        className={cn(
          // `w-60` intrinsic, `max-w-full` so it shrinks to fit a
          // narrow mobile bubble instead of overflowing its corners.
          "inline-flex w-60 max-w-full items-center gap-2 rounded-wx-sm px-3 py-2 text-xs font-medium",
          onDark
            ? "bg-wx-primary-fg/10 text-wx-primary-fg hover:bg-wx-primary-fg/20"
            : "bg-wx-bg/60 text-wx-fg hover:bg-wx-bg",
        )}
      >
        <ExternalLink size={12} className="shrink-0" />
        <span className="truncate">{t("openAudio")}</span>
      </a>
    );
  }

  // Single-row flex so play button + waveform + time counter share
  // one baseline — vertical centering "just works" without manual
  // pixel nudges. `w-60` is the intrinsic target width; `max-w-full`
  // lets it shrink to fit a narrow mobile bubble instead of
  // overflowing the rounded corners (a plain `w-full` would collapse
  // it tiny inside the shrink-wrapped bubble). `min-w-0` lets the flex
  // children shrink rather than force the row wider than its parent.
  return (
    <div className="flex w-60 max-w-full min-w-0 items-center gap-3">
      <button
        type="button"
        onClick={handlePlayPause}
        aria-label={isPlaying ? t("pauseAudio") : t("playAudio")}
        className={cn(
          "flex h-8 w-8 shrink-0 items-center justify-center rounded-full transition-opacity",
          onDark
            ? "bg-wx-primary-fg text-wx-primary hover:opacity-90"
            : "bg-wx-primary text-wx-primary-fg hover:bg-wx-primary-hover",
        )}
      >
        {!isReady ? (
          <Loader2 size={12} className="animate-spin" />
        ) : isPlaying ? (
          <Pause size={12} />
        ) : (
          // Optical centering — the play triangle's visual mass
          // sits left of the SVG bounding box.
          <Play size={12} className="translate-x-[1px]" />
        )}
      </button>
      <div ref={containerRef} className="min-w-0 flex-1" />
      <span
        className={cn(
          "shrink-0 font-mono text-[10px] tabular-nums",
          onDark ? "text-wx-primary-fg/70" : "text-wx-fg-subtle",
        )}
      >
        {isReady ? formatTime(currentTime) : "0:00"}
      </span>
    </div>
  );
}

function formatTime(time: number): string {
  const m = Math.floor(time / 60);
  const s = Math.floor(time % 60)
    .toString()
    .padStart(2, "0");
  return `${m}:${s}`;
}

/**
 * Wavesurfer's canvas can't resolve CSS opacity — for the unplayed
 * waveform tint we feed a literal `rgba()` string built from the
 * resolved foreground hex.
 */
function hexToRgba(hex: string, alpha: number): string {
  const clean = hex.replace("#", "");
  if (clean.length !== 6) return hex;
  const r = parseInt(clean.substring(0, 2), 16);
  const g = parseInt(clean.substring(2, 4), 16);
  const b = parseInt(clean.substring(4, 6), 16);
  return `rgba(${r}, ${g}, ${b}, ${alpha})`;
}
